func reflectionInterceptor(ctx context.Context, req interface{}, info *grpc.UnaryServerInfo, handler grpc.UnaryHandler) (interface{}, error) {
	if info.FullMethod == "/grpc.reflection.v1alpha.ServerReflection/ServerReflectionInfo" ||
		info.FullMethod == "/grpc.reflection.v1.ServerReflection/ServerReflectionInfo" {
		
		env := os.Getenv("ENVIRONMENT")
		if env != "development" && env != "testing" {
			return nil, status.Error(codes.PermissionDenied, "reflection is disabled in production")
		}
		
		md, ok := metadata.FromIncomingContext(ctx)
		if !ok {
			return nil, status.Error(codes.Unauthenticated, "missing metadata")
		}
		
		authTokens := md.Get("authorization")
		if len(authTokens) == 0 {
			return nil, status.Error(codes.Unauthenticated, "missing authorization token")
		}
		
		if !isValidDevToken(authTokens[0]) {
			return nil, status.Error(codes.PermissionDenied, "invalid authorization token")
		}
	}
	
	return handler(ctx, req)
}

func isValidDevToken(token string) bool {
	validToken := os.Getenv("DEV_REFLECTION_TOKEN")
	if validToken == "" {
		return false
	}
	return token == validToken
}

